Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and MSTest v3+ timeout/cancellation patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // fails test if it hangs
    public async Task FetchAsync_ReturnsContent_OnSuccess(CancellationToken cancellationToken)
    {
        // MSTest v3+ injects a CancellationToken tied to [Timeout]
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com", cancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnFailureStatus(CancellationToken cancellationToken)
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com", cancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class MockHttpMessageHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `GetAwaiter().GetResult()` needed |
| `[Timeout(ms)]` | Fails the test if it exceeds the budget; prevents hangs in CI |
| `CancellationToken` parameter | MSTest v3+ auto-injects a token linked to the timeout — pass it through to your SUT |
| `Assert.ThrowsExactlyAsync` | MSTest v3 preferred over `ThrowsExceptionAsync` (exact type match, no subclass) |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP responses |

> **Note:** The injected `CancellationToken` parameter requires **MSTest 3.3+** and `Microsoft.Testing.Platform`. If you're on an older SDK, remove the parameter and rely solely on `[Timeout]`.
